def _parse_gs_uri(uri: str):
    if not uri:
        return None, None
    m = re.match(r"^gs://([^/]+)/(.+)$", uri)
    if not m:
        return None, None
    return m.group(1), m.group(2)


def _safe_filename(name: str) -> str:
    name = os.path.basename(name or "")
